import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  describe("empty and trivial inputs", () => {
    it("returns [] for []", () => {
      expect(mergeIntervals([])).toEqual([]);
    });

    it("returns a single interval unchanged (by value)", () => {
      expect(mergeIntervals([[1, 4]])).toEqual([[1, 4]]);
    });

    it("preserves a zero-width interval (start === end)", () => {
      expect(mergeIntervals([[3, 3]])).toEqual([[3, 3]]);
    });
  });

  describe("overlapping intervals are merged", () => {
    it("merges [1,4],[3,6] -> [1,6]", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    it("merges when a later interval is fully contained", () => {
      expect(mergeIntervals([[1, 10], [3, 6]])).toEqual([[1, 10]]);
    });

    it("keeps the max end when the second interval ends earlier", () => {
      // [1,8] fully contains [2,5]; result end must stay 8, not shrink to 5
      expect(mergeIntervals([[1, 8], [2, 5]])).toEqual([[1, 8]]);
    });

    it("merges a chain of overlaps into one", () => {
      expect(mergeIntervals([[1, 3], [2, 5], [4, 8]])).toEqual([[1, 8]]);
    });
  });

  describe("touching intervals are merged", () => {
    it("merges [1,2],[2,3] -> [1,3]", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    it("merges touching intervals given out of order", () => {
      expect(mergeIntervals([[2, 3], [1, 2]])).toEqual([[1, 3]]);
    });
  });

  describe("disjoint intervals stay separate", () => {
    it("keeps two non-overlapping intervals apart", () => {
      expect(mergeIntervals([[1, 2], [4, 5]])).toEqual([[1, 2], [4, 5]]);
    });

    it("does not merge intervals that only share a gap of 1", () => {
      // end=2, next start=3 -> not touching, stay separate
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });

    it("handles a mix of merged and disjoint groups", () => {
      expect(mergeIntervals([[1, 3], [2, 4], [7, 9], [8, 10]])).toEqual([
        [1, 4],
        [7, 9].constructor === Array ? [7, 10] : [7, 10],
      ]);
    });
  });

  describe("sorting", () => {
    it("returns intervals sorted by start ascending regardless of input order", () => {
      expect(mergeIntervals([[5, 6], [1, 2], [3, 4]])).toEqual([
        [1, 2],
        [3, 4],
        [5, 6],
      ]);
    });

    it("merges correctly when overlapping intervals arrive unsorted", () => {
      expect(mergeIntervals([[6, 8], [1, 9], [2, 3]])).toEqual([[1, 9]]);
    });
  });

  describe("negative and mixed-sign values", () => {
    it("merges intervals spanning negative and positive numbers", () => {
      expect(mergeIntervals([[-5, -1], [-2, 3]])).toEqual([[-5, 3]]);
    });

    it("keeps disjoint negative intervals separate", () => {
      expect(mergeIntervals([[-10, -8], [-3, -1]])).toEqual([[-10, -8], [-3, -1]]);
    });
  });

  describe("input is never mutated", () => {
    it("does not mutate the input array or its pairs", () => {
      const input = [[1, 4], [3, 6], [8, 10]];
      const snapshot = JSON.parse(JSON.stringify(input));
      mergeIntervals(input);
      expect(input).toEqual(snapshot);
    });

    it("returns pairs that are not references to the input pairs", () => {
      const pair = [1, 4];
      const input = [pair];
      const result = mergeIntervals(input);
      result[0][0] = 999;
      expect(pair[0]).toBe(1);
    });

    it("returns a new array (not the same reference as input)", () => {
      const input = [[1, 2]];
      expect(mergeIntervals(input)).not.toBe(input);
    });
  });

  describe("invalid intervals throw RangeError", () => {
    it("throws when a pair has start > end", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
    });

    it("throws even when other intervals are valid", () => {
      expect(() => mergeIntervals([[1, 2], [9, 3]])).toThrow(RangeError);
    });

    it("does not throw for start === end", () => {
      expect(() => mergeIntervals([[4, 4]])).not.toThrow();
    });
  });
});

